import java.util.Arrays;

class Solution {
    public int numSubseq(int[] nums, int target) {
        int n = nums.length;
        int mod = 1000000007;

        Arrays.sort(nums);

        long[] power = new long[n];
        power[0] = 1;
        for (int i = 1; i < n; ++i) {
            power[i] = (power[i - 1] * 2) % mod;
        }

        int ans = 0;
        int r = n;

        for (int l = 0; l < n; ++l) {
            while (r > l && nums[l] + nums[r - 1] > target) {
                --r;
            }

            ans = (ans + (int)power[r - l]) % mod;
        }

        return ans;
    }
}
```


